func (q *Queries) UpdateEstimate(ctx context.Context, arg UpdateEstimateParams) (Estimate, error) {
	row := q.db.QueryRowContext(ctx, updateEstimate,
		arg.Number,
		arg.ParticipantID,
		arg.PlanManagerID,
		arg.Status,
		arg.IssueDate,
		arg.ValidUntil,
		arg.Subtotal,
		arg.Tax,
		arg.Total,
		arg.Notes,
		arg.BusinessSnapshot,
		arg.ClientSnapshot,
		arg.PayerSnapshot,
		arg.UpdatedAt,
		arg.TenantID,
		arg.ID,
	)
	var i Estimate
	err := row.Scan(
		&i.ID,
		&i.Uuid,
		&i.TenantID,
		&i.Number,
		&i.ParticipantID,
		&i.PlanManagerID,
		&i.Status,
		&i.IssueDate,
		&i.ValidUntil,
		&i.Subtotal,
		&i.Tax,
		&i.Total,
		&i.Notes,
		&i.ConvertedInvoiceID,
		&i.BusinessSnapshot,
		&i.ClientSnapshot,
		&i.PayerSnapshot,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

const updateEstimateStatus = `-- name: UpdateEstimateStatus :exec
UPDATE estimates SET status = ?, updated_at = ? WHERE tenant_id = ? AND id = ?
`

type UpdateEstimateStatusParams struct {
	Status    string `json:"status"`
	UpdatedAt string `json:"updated_at"`
	TenantID  int64  `json:"tenant_id"`
	ID        int64  `json:"id"`
}

func (q *Queries) UpdateEstimateStatus(ctx context.Context, arg UpdateEstimateStatusParams) error {
	_, err := q.db.ExecContext(ctx, updateEstimateStatus,
		arg.Status,
		arg.UpdatedAt,
		arg.TenantID,
		arg.ID,
	)
	return err
}
